    <script>
        // YAML Parser (simplified)
        class SimpleYAMLParser {
            static parse(yamlText) {
                const lines = yamlText.split('\n').map(l => l.trim());
                const config = {
                    states: [],
                    symbols: [],
                    blank: '_',
                    start: '',
                    transitions: {}
                };

                let currentSection = null;
                let transitionState = null;

                for (let line of lines) {
                    if (!line || line.startsWith('#')) continue;

                    if (line.includes(':')) {
                        const [key, value] = line.split(':').map(s => s.trim());

                        switch(key) {
                            case 'states':
                                currentSection = 'states';
                                break;
                            case 'symbols':
                                currentSection = 'symbols';
                                break;
                            case 'blank':
                                config.blank = value || '_';
                                break;
                            case 'start':
                                config.start = value;
                                break;
                            case 'transition':
                                transitionState = value;
                                config.transitions[transitionState] = [];
                                currentSection = 'transitions';
                                break;
                            default:
                                if (currentSection === 'transitions' && transitionState) {
                                    const parts = line.split('->').map(s => s.trim());
                                    if (parts.length === 2) {
                                        const [read, rest] = parts;
                                        const restParts = rest.split(',').map(s => s.trim());
                                        if (restParts.length === 3) {
                                            config.transitions[transitionState].push({
                                                read: read,
                                                write: restParts[0],
                                                move: restParts[1],
                                                next: restParts[2]
                                            });
                                        }
                                    }
                                }
                        }
                    } else if (currentSection === 'states' && line.startsWith('-')) {
                        config.states.push(line.substring(1).trim());
                    } else if (currentSection === 'symbols' && line.startsWith('-')) {
                        config.symbols.push(line.substring(1).trim());
                    }
                }

                return config;
            }

            static stringify(config) {
                let yaml = `# Turing Machine Configuration\n\n`;
                yaml += `states:\n`;
                config.states.forEach(state => yaml += `  - ${state}\n`);
                yaml += `\nsymbols:\n`;
                config.symbols.forEach(symbol => yaml += `  - ${symbol}\n`);
                yaml += `\nblank: ${config.blank}\n`;
                yaml += `start: ${config.start}\n\n`;

                yaml += `transitions:\n`;
                for (let state in config.transitions) {
                    yaml += `  transition: ${state}\n`;
                    config.transitions[state].forEach(t => {
                        yaml += `    ${t.read} -> ${t.write}, ${t.move}, ${t.next}\n`;
                    });
                }

                return yaml;
            }
        }

        // Turing Machine Class
        class TuringMachine {
            constructor(config) {
                this.states = config.states;
                this.symbols = config.symbols;
                this.blank = config.blank;
                this.currentState = config.start;
                this.transitions = config.transitions;
                this.tape = {};
                this.head = 0;
                this.stepCount = 0;
                this.halted = false;

                // Initialize tape at position 0
                this.tape[0] = this.blank;
            }

            read() {
                return this.tape[this.head] || this.blank;
            }

            write(symbol) {
                this.tape[this.head] = symbol;
            }

            getTransition(state, symbol) {
                if (!this.transitions[state]) return [];

                // Find all matching transitions
                const matches = this.transitions[state].filter(t => 
                    t.read === symbol || t.read === '*'
                );

                return matches;
            }

            step(stochastic = false) {
                if (this.halted) return false;

                const currentSymbol = this.read();
                const transitions = this.getTransition(this.currentState, currentSymbol);

                if (transitions.length === 0) {
                    this.halted = true;
                    return false;
                }

                // Choose transition
                let transition;
                if (stochastic && transitions.length > 1) {
                    // Random choice with probability
                    const weights = transitions.map(t => t.probability || 1);
                    const totalWeight = weights.reduce((a, b) => a + b, 0);
                    let random = Math.random() * totalWeight;

                    for (let i = 0; i < transitions.length; i++) {
                        random -= weights[i];
                        if (random <= 0) {
                            transition = transitions[i];
                            break;
                        }
                    }
                } else {
                    transition = transitions[0];
                }

                if (!transition) {
                    this.halted = true;
                    return false;
                }

                // Execute transition
                if (transition.write !== '*') {
                    this.write(transition.write);
                }

                // Move head
                switch(transition.move) {
                    case 'L': this.head--; break;
                    case 'R': this.head++; break;
                    case 'S': break;
                }

                // Update state
                if (transition.next && transition.next !== '*') {
                    this.currentState = transition.next;
                }

                // Ensure tape cell exists
                if (!(this.head in this.tape)) {
                    this.tape[this.head] = this.blank;
                }

                this.stepCount++;
                return transition;
            }

            reset() {
                this.tape = {};
                this.head = 0;
                this.currentState = this.startState;
                this.stepCount = 0;
                this.halted = false;
                this.tape[0] = this.blank;
            }

            getTapeSegment(start, count) {
                const segment = [];
                for (let i = start; i < start + count; i++) {
                    segment.push({
                        pos: i,
                        value: this.tape[i] || this.blank
                    });
                }
                return segment;
            }
