                        { read: '0', write: '0', move: 'R', next: 'q0' },
                        { read: '_', write: '1', move: 'S', next: 'halt' }
                    ]
                }
            };

            currentConfig = defaultConfig;
            configEditor.value = SimpleYAMLParser.stringify(defaultConfig);
            initializeMachine(defaultConfig);
