        // Initialize machine
        function initializeMachine(config) {
            try {
                machine = new TuringMachine(config);
                currentConfig = config;
                updateDisplay();
                logToConsole('Machine initialized', 'success');
            } catch (error) {
                logToConsole('Error initializing machine: ' + error.message, 'error');
            }
        }

        // Update display
        function updateDisplay() {
            if (!machine) return;

            updateTape();
            updateStats();
        }

