                    line.style.color = '#dc3545';
                    line.innerHTML = prefix + '❌ ' + message;
                    break;
                case 'success':
                    line.style.color = '#28a745';
                    line.innerHTML = prefix + '✓ ' + message;
                    break;
                case 'step':
                    line.style.color = '#007bff';
                    line.innerHTML = prefix + '→ ' + message;
                    break;
                default:
                    line.innerHTML = prefix + message;
            }

            consoleElement.appendChild(line);
            consoleElement.scrollTop = consoleElement.scrollHeight;

            // Keep only last 100 lines
            const lines = consoleElement.querySelectorAll('.console-line');
            if (lines.length > 100) {
                lines[0].remove();
            }
        }

        // Clear console
        function clearConsole() {
            const consoleElement = document.querySelector('.console');
            consoleElement.innerHTML = '<div class="console-line" style="color: #6c757d;">Console output will appear here...</div>';
        }

        // Start execution
        function startExecution() {
            if (!machine) {
                alert('Please load a configuration first!');
                return;
            }

            if (machine.halted) {
                resetMachine();
            }

            isRunning = true;
            document.getElementById('runBtn').disabled = true;
            document.getElementById('pauseBtn').disabled = false;

            const speed = parseInt(speedSlider.value);
            const delay = Math.max(50, 500 / speed);

            runInterval = setInterval(() => {
                if (!isRunning || machine.halted) {
                    pauseExecution();
                    return;
                }

                const transition = machine.step(stochasticMode.checked);
                if (transition) {
                    logToConsole(
                        `State: ${machine.currentState} | Read: ${transition.read} | Write: ${transition.write} | Move: ${transition.move} | Next: ${transition.next}`,
                        'step'
                    );
                    updateDisplay();
                } else {
                    logToConsole('Machine halted', 'success');
                    pauseExecution();
                }
            }, delay);
        }

        // Pause execution
        function pauseExecution() {
            isRunning = false;
            clearInterval(runInterval);
            runInterval = null;
            document.getElementById('runBtn').disabled = false;
            document.getElementById('pauseBtn').disabled = true;
        }

