                    config = {
                        states: ['A', 'B', 'C', 'H'],
                        symbols: ['0', '1', '_'],
                        blank: '_',
                        start: 'A',
                        transitions: {
                            'A': [
                                { read: '0', write: '1', move: 'R', next: 'B' },
                                { read: '1', write: '1', move: 'L', next: 'C' }
                            ],
                            'B': [
                                { read: '0', write: '1', move: 'L', next: 'A' },
                                { read: '1', write: '1', move: 'R', next: 'B' }
                            ],
                            'C': [
                                { read: '0', write: '1', write: 'L', next: 'B' },
                                { read: '1', write: '1', move: 'S', next: 'H' }
                            ]
                        }
                    };
                    break;

                case 'unary':
                    config = {
                        states: ['q0', 'q1', 'q2', 'halt'],
                        symbols: ['1', '+', '=', '_'],
                        blank: '_',
                        start: 'q0',
                        transitions: {
                            'q0': [
                                { read: '1', write: '1', move: 'R', next: 'q0' },
                                { read: '+', write: '1', move: 'R', next: 'q1' },
                                { read: '=', write: '=', move: 'L', next: 'q2' }
                            ],
                            'q1': [
                                { read: '1', write: '1', move: 'R', next: 'q1' },
                                { read: '=', write: '=', move: 'L', next: 'q2' }
                            ],
                            'q2': [
                                { read: '1', write: '=', move: 'L', next: 'halt' }
                            ]
                        }
                    };
                    break;
            }

            if (config) {
                configEditor.value = SimpleYAMLParser.stringify(config);
                initializeMachine(config);
                logToConsole(`Loaded ${preset} preset`, 'success');
            }
        }

        // Save config
        function saveConfig() {
            const configText = configEditor.value;
            const blob = new Blob([configText], { type: 'text/yaml' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'turing-config-' + Date.now() + '.yaml';
            a.click();
            URL.revokeObjectURL(url);
            logToConsole('Configuration saved', 'success');
        }

        // Load config from file
        function loadConfig() {
            document.getElementById('fileInput').click();
        }

        // Handle file input
        document.getElementById('fileInput').addEventListener('change', function(e) {
            const file = e.target.files[0];
            if (!file) return;

            const reader = new FileReader();
            reader.onload = function(event) {
                configEditor.value = event.target.result;
                loadConfigFromEditor();
            };
            reader.readAsText(file);
        });

        // Screenshot
        function screenshot() {
            html2canvas(document.body).then(canvas => {
                canvas.toBlob(blob => {
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = 'turing-sim-' + Date.now() + '.png';
                    a.click();
                    URL.revokeObjectURL(url);
                });
            });
            logToConsole('Screenshot saved', 'success');
        }

        // Speed control
        speedSlider.addEventListener('input', function() {
            speedValue.textContent = this.value;
            if (isRunning) {
                pauseExecution();
                startExecution();
            }
        });

        // Keyboard shortcuts
        document.addEventListener('keydown', function(e) {
            if (e.ctrlKey || e.metaKey) return; // Don't override browser shortcuts

            switch(e.key) {
                case ' ':
                    e.preventDefault();
                    if (isRunning) pauseExecution();
                    else startExecution();
                    break;
                case 'r':
                    if (e.shiftKey) resetMachine();
                    break;
                case 's':
                    stepForward();
                    break;
            }
        });

        // Config editor auto-save
        configEditor.addEventListener('input', function() {
            clearTimeout(window.configDebounce);
            window.configDebounce = setTimeout(() => {
                loadConfigFromEditor();
            }, 1000);
        });

        // HTML2Canvas for screenshots
        const html2canvas = (function() {
            // Minimal implementation - in production, you'd use the real html2canvas library
            return {
                canvas: document.createElement('canvas'),
                toBlob: function(callback) {
                    const canvas = document.createElement('canvas');
                    canvas.width = window.innerWidth;
                    canvas.height = window.innerHeight;
                    const ctx = canvas.getContext('2d');
                    ctx.fillStyle = '#ffffff';
                    ctx.fillRect(0, 0, canvas.width, canvas.height);
                    ctx.fillStyle = '#000000';
                    ctx.font = '20px sans-serif';
                    ctx.fillText('Screenshots require html2canvas library', 50, 50);
                    canvas.toBlob(callback);
                }
            };
        })();

        // Initialize
        initializeDefaultConfig();
        logToConsole('Turing Machine Simulator ready!', 'success');
        logToConsole('Keyboard shortcuts: Space (run/pause), S (step), Shift+R (reset)', 'info');
    </script>
